  UNION ALL SELECT "user_pseudo_id", "event_date", "user_first_touch_timestamp", "event_name" FROM "FIREBASE"."ANALYTICS_153293282"."EVENTS_20180929" WHERE "event_name" = 'session_start'
  UNION ALL SELECT "user_pseudo_id", "event_date", "user_first_touch_timestamp", "event_name" FROM "FIREBASE"."ANALYTICS_153293282"."EVENTS_20180930" WHERE "event_name" = 'session_start'
  UNION ALL SELECT "user_pseudo_id", "event_date", "user_first_touch_timestamp", "event_name" FROM "FIREBASE"."ANALYTICS_153293282"."EVENTS_20181001" WHERE "event_name" = 'session_start'
  UNION ALL SELECT "user_pseudo_id", "event_date", "user_first_touch_timestamp", "event_name" FROM "FIREBASE"."ANALYTICS_153293282"."EVENTS_20181002" WHERE "event_name" = 'session_start'
), session_events AS (
  SELECT
    "user_pseudo_id",
    TO_DATE("event_date", 'YYYYMMDD') AS event_date_dt,
    DATE(TO_TIMESTAMP("user_first_touch_timestamp" / 1000000)) AS first_touch_date
  FROM all_events
  WHERE TO_DATE("event_date", 'YYYYMMDD') = DATE(TO_TIMESTAMP("user_first_touch_timestamp" / 1000000))
), first_sessions AS (
  SELECT
    "user_pseudo_id",
    MIN(event_date_dt) AS first_session_date
  FROM session_events
  GROUP BY "user_pseudo_id"
), cohorts AS (
  SELECT
    "user_pseudo_id",
    DATE_TRUNC('week', first_session_date) AS cohort_week
  FROM first_sessions
  WHERE cohort_week BETWEEN '2018-07-09' AND '2018-09-17'
), cohort_users AS (
  SELECT
    cohort_week,
    COUNT(DISTINCT "user_pseudo_id") AS total_users
  FROM cohorts
  GROUP BY cohort_week
), all_session_events AS (
  SELECT
    "user_pseudo_id",
    TO_DATE("event_date", 'YYYYMMDD') AS event_date_dt
  FROM all_events
), retained_users AS (
  SELECT
    c.cohort_week,
    c."user_pseudo_id"
  FROM cohorts c
  INNER JOIN all_session_events s ON c."user_pseudo_id" = s."user_pseudo_id"
    AND s.event_date_dt >= DATEADD(day, 14, c.cohort_week)
    AND s.event_date_dt < DATEADD(day, 21, c.cohort_week)
  GROUP BY c.cohort_week, c."user_pseudo_id"
), retained_counts AS (
  SELECT
    cohort_week,
    COUNT(DISTINCT "user_pseudo_id") AS retained_users
  FROM retained_users
  GROUP BY cohort_week
)
SELECT
  c.cohort_week,
  ROUND(COALESCE(r.retained_users, 0) * 100.0 / c.total_users, 2) AS week_2_retention_rate
FROM cohort_users c
LEFT JOIN retained_counts r ON c.cohort_week = r.cohort_week
ORDER BY c.cohort_week;